                      border: `1px solid ${stmt.correct === true ? "rgba(100, 180, 120, 0.4)" : stmt.correct === false ? "rgba(180, 90, 90, 0.4)" : "rgba(180, 150, 60, 0.4)"}`,
                      cursor: "pointer",
